import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Ultrawork-Modus: Alle Funktionen aktivieren | oh-my-opencode","description":"Lernen Sie den Ultrawork-Modus von oh-my-opencode kennen, um alle Funktionen mit einem Befehl zu aktivieren. Aktiviert parallele Agenten, erzwungene Fertigstellung und das Kategorie-+ Skills-System.","frontmatter":{"title":"Ultrawork-Modus: Alle Funktionen aktivieren | oh-my-opencode","sidebarTitle":"Ultrawork-Modus","subtitle":"Ultrawork-Modus: Alle Funktionen mit einem Befehl aktivieren","description":"Lernen Sie den Ultrawork-Modus von oh-my-opencode kennen, um alle Funktionen mit einem Befehl zu aktivieren. Aktiviert parallele Agenten, erzwungene Fertigstellung und das Kategorie-+ Skills-System.","tags":["ultrawork","Hintergrundaufgaben","Agent-Zusammenarbeit"],"prerequisite":["start-installation","start-sisyphus-orchestrator"],"order":30},"headers":[],"relativePath":"de/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"de/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),a={name:"de/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function l(o,e,s,d,u,g){return i(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="ultrawork-modus-alle-funktionen-mit-einem-befehl-aktivieren" tabindex="-1">Ultrawork-Modus: Alle Funktionen mit einem Befehl aktivieren <a class="header-anchor" href="#ultrawork-modus-alle-funktionen-mit-einem-befehl-aktivieren" aria-label="Permalink to &quot;Ultrawork-Modus: Alle Funktionen mit einem Befehl aktivieren&quot;">​</a></h1><h2 id="was-sie-lernen-werden" tabindex="-1">Was Sie lernen werden <a class="header-anchor" href="#was-sie-lernen-werden" aria-label="Permalink to &quot;Was Sie lernen werden&quot;">​</a></h2><ul><li>Alle erweiterten Funktionen von oh-my-opencode mit einem einzigen Befehl aktivieren</li><li>Mehrere KI-Agenten wie ein echtes Team parallel arbeiten lassen</li><li>Manuelles Konfigurieren mehrerer Agenten und Hintergrundaufgaben vermeiden</li><li>Die Designphilosophie und Best Practices des Ultrawork-Modus verstehen</li></ul><h2 id="ihre-aktuellen-herausforderungen" tabindex="-1">Ihre aktuellen Herausforderungen <a class="header-anchor" href="#ihre-aktuellen-herausforderungen" aria-label="Permalink to &quot;Ihre aktuellen Herausforderungen&quot;">​</a></h2><p>Sie haben während der Entwicklung möglicherweise folgende Situationen erlebt:</p><ul><li><strong>Zu viele Funktionen, keine Ahnung, wie man sie nutzt</strong>: Sie haben 10 spezialisierte Agenten, Hintergrundaufgaben, LSP-Tools, wissen aber nicht, wie Sie sie schnell aktivieren können</li><li><strong>Manuelle Konfiguration erforderlich</strong>: Jede komplexe Aufgabe erfordert manuelles Festlegen von Agenten, Hintergrundparallelität und anderen Einstellungen</li><li><strong>Ineffiziente Agent-Zusammenarbeit</strong>: Aufrufen von Agenten in Serie, Verschwendung von Zeit und Kosten</li><li><strong>Aufgaben stecken mittendrin fest</strong>: Agenten haben nicht genug Motivation und Zwänge, um Aufgaben zu beenden</li></ul><p>Dies alles beeinträchtigt Ihre Fähigkeit, die wahre Kraft von oh-my-opencode zu entfesseln.</p><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Der <strong>Ultrawork-Modus</strong> ist der &quot;Mit einem Klick alles aktivieren&quot;-Mechanismus von oh-my-opencode.</p><div class="info custom-block"><p class="custom-block-title">Was ist der Ultrawork-Modus?</p><p>Der Ultrawork-Modus ist ein spezieller Arbeitsmodus, der durch ein Schlüsselwort ausgelöst wird. Wenn Ihre Eingabe das Schlüsselwort <code>ultrawork</code> oder seine Abkürzung <code>ulw</code> enthält, aktiviert das System automatisch alle erweiterten Funktionen: parallele Hintergrundaufgaben, tiefe Erkundung, erzwungene Fertigstellung, Multi-Agent-Zusammenarbeit und mehr.</p></div><h3 id="designphilosophie" tabindex="-1">Designphilosophie <a class="header-anchor" href="#designphilosophie" aria-label="Permalink to &quot;Designphilosophie&quot;">​</a></h3><p>Der Ultrawork-Modus basiert auf den folgenden Kernprinzipien (aus dem <a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork-Manifest</a>):</p><table tabindex="0"><thead><tr><th>Prinzip</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>Menschliches Eingreifen ist ein Fehlersignal</strong></td><td>Wenn Sie ständig KI-Ausgaben korrigieren müssen, bedeutet das, dass ein Problem mit dem Systemdesign vorliegt</td></tr><tr><td><strong>Ununterscheidbarer Code</strong></td><td>Von KI geschriebener Code sollte von Code von Senior-Ingenieuren ununterscheidbar sein</td></tr><tr><td><strong>Kognitive Belastung minimieren</strong></td><td>Sie müssen nur sagen, &quot;was zu tun ist&quot;, Agenten sind für &quot;wie es zu tun ist&quot; verantwortlich</td></tr><tr><td><strong>Vorhersehbar, konsistent, delegierbar</strong></td><td>Agenten sollten so stabil und zuverlässig wie ein Compiler sein</td></tr></tbody></table><h3 id="aktivierungsmechanismus" tabindex="-1">Aktivierungsmechanismus <a class="header-anchor" href="#aktivierungsmechanismus" aria-label="Permalink to &quot;Aktivierungsmechanismus&quot;">​</a></h3><p>Wenn das System das Schlüsselwort <code>ultrawork</code> oder <code>ulw</code> erkennt:</p><ol><li><strong>Maximale Präzisionsmodus einstellen</strong>: <code>message.variant = &quot;max&quot;</code></li><li><strong>Toast-Benachrichtigung anzeigen</strong>: &quot;Ultrawork-Modus aktiviert - Maximale Präzision engagiert. Alle Agenten zur Verfügung.&quot;</li><li><strong>Vollständige Anweisungen injizieren</strong>: Injiziert 200+ Zeilen ULTRAWORK-Anweisungen an Agenten, einschließlich: <ul><li>Erfordert 100%ige Sicherheit vor Beginn der Implementierung</li><li>Erfordert parallele Verwendung von Hintergrundaufgaben</li><li>Erzwungene Verwendung des Kategorie-+ Skills-Systems</li><li>Erzwungene Fertigstellungsverifizierung (TDD-Workflow)</li><li>Verbietet jegliche &quot;Ich kann das nicht&quot;-Ausreden</li></ul></li></ol><h2 id="schritt-fur-schritt" tabindex="-1">Schritt-für-Schritt <a class="header-anchor" href="#schritt-fur-schritt" aria-label="Permalink to &quot;Schritt-für-Schritt&quot;">​</a></h2><h3 id="schritt-1-ultrawork-modus-auslosen" tabindex="-1">Schritt 1: Ultrawork-Modus auslösen <a class="header-anchor" href="#schritt-1-ultrawork-modus-auslosen" aria-label="Permalink to &quot;Schritt 1: Ultrawork-Modus auslösen&quot;">​</a></h3><p>Geben Sie eine Eingabe ein, die das Schlüsselwort <code>ultrawork</code> oder <code>ulw</code> enthält, in OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork develop a REST API</span></span></code></pre></div><p>Oder noch prägnanter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw add user authentication</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>:</p><ul><li>Eine Toast-Benachrichtigung poppt auf der Schnittstelle auf: &quot;Ultrawork-Modus aktiviert&quot;</li><li>Die Agent-Antwort beginnt mit &quot;ULTRAWORK MODUS AKTIVIERT!&quot;</li></ul><h3 id="schritt-2-anderungen-im-agentenverhalten-beobachten" tabindex="-1">Schritt 2: Änderungen im Agentenverhalten beobachten <a class="header-anchor" href="#schritt-2-anderungen-im-agentenverhalten-beobachten" aria-label="Permalink to &quot;Schritt 2: Änderungen im Agentenverhalten beobachten&quot;">​</a></h3><p>Nach dem Aktivieren des Ultrawork-Modus werden Agenten:</p><ol><li><p><strong>Parallele Erkundung der Codebasis</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;find existing API patterns&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;find test infrastructure&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;find authentication best practices&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Plan-Agent aufrufen, um Arbeitsplan zu erstellen</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;create detailed plan based on gathered context&quot;)</span></span></code></pre></div></li><li><p><strong>Kategorie-+ Skills verwenden, um Aufgaben auszuführen</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>Sie sollten sehen</strong>:</p><ul><li>Mehrere Hintergrundaufgaben, die gleichzeitig laufen</li><li>Agenten rufen aktiv spezialisierte Agenten auf (Oracle, Librarian, Explore)</li><li>Vollständige Testpläne und Arbeitsaufschlüsselung</li><li>Aufgaben führen weiter aus, bis 100% abgeschlossen</li></ul><h3 id="schritt-3-aufgabenerfullung-verifizieren" tabindex="-1">Schritt 3: Aufgabenerfüllung verifizieren <a class="header-anchor" href="#schritt-3-aufgabenerfullung-verifizieren" aria-label="Permalink to &quot;Schritt 3: Aufgabenerfüllung verifizieren&quot;">​</a></h3><p>Nachdem Agenten fertig sind, werden sie:</p><ol><li><strong>Verifizierungsnachweise zeigen</strong>: Tatsächliche Testlaufausgaben, manuelle Verifizierungsbeschreibungen</li><li><strong>Alle TODOs als abgeschlossen bestätigen</strong>: Wird nicht vorzeitig Fertigstellung erklären</li><li><strong>Erledigte Arbeit zusammenfassen</strong>: Auflisten, was getan wurde und warum</li></ol><p><strong>Sie sollten sehen</strong>:</p><ul><li>Klare Testergebnisse (nicht &quot;sollte funktionieren&quot;)</li><li>Alle Probleme gelöst</li><li>Keine unvollständige TODO-Liste</li></ul><h2 id="kontrollpunkt-✅" tabindex="-1">Kontrollpunkt ✅ <a class="header-anchor" href="#kontrollpunkt-✅" aria-label="Permalink to &quot;Kontrollpunkt ✅&quot;">​</a></h2><p>Nach Abschluss der obigen Schritte bestätigen Sie:</p><ul><li>[ ] Sie sehen eine Toast-Benachrichtigung nach Eingabe von <code>ulw</code></li><li>[ ] Die Agent-Antwort beginnt mit &quot;ULTRAWORK MODUS AKTIVIERT!&quot;</li><li>[ ] Sie beobachten parallele Hintergrundaufgaben, die laufen</li><li>[ ] Agenten verwenden das Kategorie-+ Skills-System</li><li>[ ] Es gibt Verifizierungsnachweise nach Aufgabenerfüllung</li></ul><p>Wenn ein Punkt fehlschlägt, überprüfen Sie:</p><ul><li>Ist das Schlüsselwort richtig geschrieben (<code>ultrawork</code> oder <code>ulw</code>)</li><li>Sind Sie in der Hauptsitzung (Hintergrundaufgaben lösen den Modus nicht aus)</li><li>Ist die Konfigurationsdatei mit relevanten Funktionen aktiviert</li></ul><h2 id="wann-sie-diese-technik-verwenden-sollten" tabindex="-1">Wann Sie diese Technik verwenden sollten <a class="header-anchor" href="#wann-sie-diese-technik-verwenden-sollten" aria-label="Permalink to &quot;Wann Sie diese Technik verwenden sollten&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Szenario</th><th>Ultrawork verwenden</th><th>Normaler Modus</th></tr></thead><tbody><tr><td><strong>Komplexe neue Funktionen</strong></td><td>✅ Empfohlen (erfordert Multi-Agent-Zusammenarbeit)</td><td>❌ Möglicherweise nicht effizient genug</td></tr><tr><td><strong>Dringende Fixes</strong></td><td>✅ Empfohlen (benötigt schnelle Diagnose und Erkundung)</td><td>❌ Möglicherweise Kontext verpassen</td></tr><tr><td><strong>Einfache Änderungen</strong></td><td>❌ Übertrieben (verschwendet Ressourcen)</td><td>✅ Geeigneter</td></tr><tr><td><strong>Schnelle Ideengültigkeit</strong></td><td>❌ Übertrieben</td><td>✅ Geeigneter</td></tr></tbody></table><p><strong>Faustregel</strong>:</p><ul><li>Aufgabe umfasst mehrere Module oder Systeme → Verwenden Sie <code>ulw</code></li><li>Tiefe Erforschung der Codebasis erforderlich → Verwenden Sie <code>ulw</code></li><li>Mehrere spezialisierte Agenten aufrufen müssen → Verwenden Sie <code>ulw</code></li><li>Einzelne Datei kleine Änderung → <code>ulw</code> nicht erforderlich</li></ul><h2 id="haufige-fallstricke" tabindex="-1">Häufige Fallstricke <a class="header-anchor" href="#haufige-fallstricke" aria-label="Permalink to &quot;Häufige Fallstricke&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Wichtige Hinweise</p><p><strong>1. Verwenden Sie nicht <code>ulw</code> in jeder Eingabe</strong></p><p>Der Ultrawork-Modus injiziert eine große Menge an Anweisungen, was für einfache Aufgaben übertrieben ist. Verwenden Sie ihn nur für komplexe Aufgaben, die wirklich Multi-Agent-Zusammenarbeit, parallele Erkundung und tiefe Analyse erfordern.</p><p><strong>2. Hintergrundaufgaben lösen den Ultrawork-Modus nicht aus</strong></p><p>Der Schlüsselwort-Detector überspringt Hintergrundsitzungen, um ein falsches Injizieren des Modus in Sub-Agenten zu vermeiden. Der Ultrawork-Modus funktioniert nur in der Hauptsitzung.</p><p><strong>3. Stellen Sie sicher, dass die Provider-Konfiguration korrekt ist</strong></p><p>Der Ultrawork-Modus basiert auf mehreren KI-Modellen, die parallel arbeiten. Wenn bestimmte Provider nicht konfiguriert oder nicht verfügbar sind, können Agenten möglicherweise keine spezialisierten Agenten aufrufen.</p></div><h2 id="lektion-zusammenfassung" tabindex="-1">Lektion Zusammenfassung <a class="header-anchor" href="#lektion-zusammenfassung" aria-label="Permalink to &quot;Lektion Zusammenfassung&quot;">​</a></h2><p>Der Ultrawork-Modus erreicht das Designziel &quot;Alle Funktionen mit einem Befehl aktivieren&quot; durch Schlüsselwort-Auslösung:</p><ul><li><strong>Einfach zu verwenden</strong>: Geben Sie einfach <code>ulw</code> ein, um zu aktivieren</li><li><strong>Automatische Zusammenarbeit</strong>: Agenten rufen automatisch andere Agenten auf und führen Hintergrundaufgaben parallel aus</li><li><strong>Erzwungene Fertigstellung</strong>: Vollständiger Verifizierungsmechanismus garantiert 100%ige Fertigstellung</li><li><strong>Null-Konfiguration</strong>: Kein manuelles Festlegen von Agentenprioritäten, Parallelitätsgrenzen usw. erforderlich</li></ul><p>Denken Sie daran: Der Ultrawork-Modus ist so konzipiert, dass Agenten wie ein echtes Team arbeiten. Sie müssen nur Absicht ausdrücken, Agenten sind für die Ausführung verantwortlich.</p><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../../platforms/provider-setup/">Provider-Konfiguration</a></strong> kennen.</p><p>Sie lernen:</p><ul><li>Wie Sie mehrere Provider wie Anthropic, OpenAI, Google konfigurieren</li><li>Wie die Multi-Modell-Strategie automatisch degradiert und optimale Modelle auswählt</li><li>Wie Sie Provider-Verbindungen und Kontingentnutzung testen</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Speicherorte zu erweitern</strong></summary><blockquote><p>Zuletzt aktualisiert: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummern</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>KEYWORD_DETECTORS</code>: Konfiguration des Schlüsselwort-Detectors, einschließlich drei Modi: ultrawork, search, analyze</li><li><code>CODE_BLOCK_PATTERN</code>: Codeblock-Regex-Muster, verwendet zum Filtern von Schlüsselwörtern in Codeblöcken</li><li><code>INLINE_CODE_PATTERN</code>: Inline-Code-Regex-Muster, verwendet zum Filtern von Schlüsselwörtern in Inline-Code</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>createKeywordDetectorHook()</code>: Erstellt Schlüsselwort-Detector Hook, hört auf UserPromptSubmit-Ereignis</li><li><code>detectKeywordsWithType()</code>: Erkennt Schlüsselwörter im Text und gibt Typ zurück (ultrawork/search/analyze)</li><li><code>getUltraworkMessage()</code>: Generiert vollständige ULTRAWORK-Modus-Anweisungen (wählt Planner oder normalen Modus basierend auf Agententyp)</li><li><code>removeCodeBlocks()</code>: Entfernt Codeblöcke aus Text, um das Auslösen von Schlüsselwörtern in Codeblöcken zu vermeiden</li></ul><p><strong>Geschäftsregeln</strong>:</p><table tabindex="0"><thead><tr><th>Regel-ID</th><th>Regelbeschreibung</th><th>Tag</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>Aktiviert Ultrawork-Modus, wenn &quot;ultrawork&quot; oder &quot;ulw&quot; erkannt wird</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-2</td><td>Ultrawork-Modus setzt <code>message.variant = &quot;max&quot;</code></td><td>[Fact]</td></tr><tr><td>BR-4.8.4-3</td><td>Ultrawork-Modus zeigt Toast-Benachrichtigung: &quot;Ultrawork-Modus aktiviert&quot;</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-4</td><td>Hintergrundaufgaben-Sitzungen überspringen Schlüsselwort-Erkennung, um Modus-Injektion zu vermeiden</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-5</td><td>Nicht-Hauptsitzungen erlauben nur ultrawork-Schlüsselwort, blockieren andere Modus-Injektion</td><td>[Fact]</td></tr></tbody></table></details>`,54)])])}const p=n(a,[["render",l]]);export{c as __pageData,p as default};
